mapper.select:
CALL UNIV.SP_LSSN_CQI_AGGR_PROC_PROC(

    #{yy, jdbcType=VARCHAR, mode=IN}
    ,#{inputUserId, jdbcType=VARCHAR, mode=IN}
    ,#{remoteAddr, jdbcType=VARCHAR, mode=IN}
    ,#{resultMessage, jdbcType=VARCHAR, mode=OUT}
    ,#{resultCode, jdbcType=INTEGER, mode=OUT}
    )

/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.findCqiOrzgDscList */
SELECT DISTINCT EMO.MAPPED_ORGID AS ORGID , COMM.FN_ORGNM(COMM.FN_ORG_LVL_ID(EMO.MAPPED_ORGID,'200')) AS UNI_NM , COMM.FN_ORGNM(EMO.MAPPED_ORGID) AS ORGZ_NM , CO.HR_INST_ID , CO.USE_YN , DECODE(CO.DEPT_LOCT_CD,'1','죽전','천안') AS DEPT_LOCT_NM , CO.ORGZ_SORT_OER , M.YY , VLOD.COLL_CD , VLOD.DPMT_CD , VLOD.MJ_CD , VLOD.DEPT_LOCT_CD /*, M.RMK*/ , NVL(M.SUBMIT_YN,'0') AS SUBMIT_YN , CASE WHEN NVL(M.SUBMIT_YN,'0')='0' THEN '' ELSE M.SUBMIT_UID END AS SUBMIT_UID , CASE WHEN NVL(M.SUBMIT_YN,'0')='0' THEN '' ELSE E_SUB.EMPNM END AS SUBMIT_UNM , E_SUB.MEM_PSTN_NM , E_SUB.WKGR_NM , CASE WHEN NVL(M.SUBMIT_YN,'0')='0' THEN '' ELSE TO_CHAR(M.SUBMIT_DM,'YYYY-MM-DD') END AS SUBMIT_DM , NVL(M.CLOSE_YN,'0') AS CLOSE_YN , CASE WHEN NVL(M.CLOSE_YN,'0')='0' THEN '' ELSE M.CLOSE_UID END AS CLOSE_UID , CASE WHEN NVL(M.CLOSE_YN,'0')='0' THEN '' ELSE E_CLS.EMPNM END AS CLOSE_UNM , CASE WHEN NVL(M.CLOSE_YN,'0')='0' THEN '' ELSE TO_CHAR(M.CLOSE_DM,'YYYY-MM-DD') END AS CLOSE_DM , NVL(M.INPUT_UID,'') AS INPUT_UID , E_INP.EMPNM AS INPUT_UNM , TO_CHAR(M.INPUT_DM,'YYYY-MM-DD HH24:MI:SS') AS INPUT_DM , NVL(M.LTST_UPD_UID,'') AS LTST_UPD_UID , E_UPD.EMPNM AS LTST_UPD_UNM , TO_CHAR(M.LTST_UPD_DM,'YYYY-MM-DD HH24:MI:SS') AS LTST_UPD_DM FROM UNIV.EFLN_MAPPED_ORGZ EMO JOIN UNIV.VW_LSSN_ORGZ_DET VLOD ON EMO.MAPPED_ORGID = VLOD.ORGID JOIN COMM.COMM_ORGZ CO ON EMO.MAPPED_ORGID = CO.ORGID LEFT JOIN ( SELECT * FROM ( SELECT S1.* , ROW_NUMBER() OVER ( PARTITION BY S1.YY, S1.ORGID, S1.CQI_DIV_CD ORDER BY NVL(S1.LTST_UPD_DM, S1.INPUT_DM) DESC, S1.INPUT_DM DESC) AS RN FROM UNIV.MCQI_MASTER S1 WHERE S1.YY = #{yy} /* :YY */ AND S1.CQI_DIV_CD = '0001' /* 전공 */ ) WHERE RN = 1 ) M ON EMO.MAPPED_ORGID = M.ORGID LEFT JOIN ADMI.VW_EMP_BAS E_SUB ON M.SUBMIT_UID = E_SUB.EMPID LEFT JOIN ADMI.VW_EMP_BAS E_CLS ON M.CLOSE_UID = E_CLS.EMPID LEFT JOIN ADMI.VW_EMP_BAS E_INP ON M.PFLT_ID = E_INP.EMPID LEFT JOIN ADMI.VW_EMP_BAS E_UPD ON M.LTST_UPD_UID = E_UPD.EMPID WHERE EMO.WOK_CD = 'MCQI' AND EMO.YY = #{yy}
AND vlod.coll_cd = #{collCd}
AND vlod.dpmt_cd = #{dpmtCd}
AND vlod.mj_cd = #{mjCd}
AND vlod.dept_loct_cd = #{deptLoctCd}
AND nvl(cqi.submit_yn,0) =#{submitYn}
AND nvl(cqi.close_yn,0) =#{closeYn}
order by co.orgz_sort_oer

/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.findMcqiContDscList - 기준: MCQI_MASTER + MCQI_COMP_DSC - 올해 값 없으면 전년도 D1~D10 이월 */ WITH CUR_COMP AS ( SELECT YY, ORGID, PFLT_ID, CQI_COMP_CD, CQI_COMP_YN FROM UNIV.MCQI_COMP_DSC WHERE YY = #{yy}
AND PFLT_ID = #{pfltId}
AND CQI_DIV_CD = '0001' ), PREV_COMP AS ( SELECT YY, ORGID, PFLT_ID, CQI_COMP_CD, CQI_COMP_YN FROM UNIV.MCQI_COMP_DSC WHERE YY = TO_CHAR(TO_NUMBER(#{yy}) - 1)
AND PFLT_ID = #{pfltId}
AND CQI_DIV_CD = '0001' ), CUR_AGG AS ( SELECT ORGID, MAX(CASE WHEN CQI_COMP_CD = '330' THEN CQI_COMP_YN END) AS D1_YN, MAX(CASE WHEN CQI_COMP_CD = '340' THEN CQI_COMP_YN END) AS D2_YN, MAX(CASE WHEN CQI_COMP_CD = '350' THEN CQI_COMP_YN END) AS D3_YN, MAX(CASE WHEN CQI_COMP_CD = '360' THEN CQI_COMP_YN END) AS D4_YN, MAX(CASE WHEN CQI_COMP_CD = '130' THEN CQI_COMP_YN END) AS D5_YN, MAX(CASE WHEN CQI_COMP_CD = '140' THEN CQI_COMP_YN END) AS D6_YN, MAX(CASE WHEN CQI_COMP_CD = '150' THEN CQI_COMP_YN END) AS D7_YN, MAX(CASE WHEN CQI_COMP_CD = '230' THEN CQI_COMP_YN END) AS D8_YN, MAX(CASE WHEN CQI_COMP_CD = '240' THEN CQI_COMP_YN END) AS D9_YN, MAX(CASE WHEN CQI_COMP_CD = '250' THEN CQI_COMP_YN END) AS D10_YN, -- 올해 하나라도 값이 있는지 여부 SUM(CASE WHEN CQI_COMP_YN IS NOT NULL THEN 1 ELSE 0 END) AS CUR_CNT FROM CUR_COMP GROUP BY ORGID ), PREV_AGG AS ( SELECT ORGID, MAX(CASE WHEN CQI_COMP_CD = '330' THEN CQI_COMP_YN END) AS D1_YN, MAX(CASE WHEN CQI_COMP_CD = '340' THEN CQI_COMP_YN END) AS D2_YN, MAX(CASE WHEN CQI_COMP_CD = '350' THEN CQI_COMP_YN END) AS D3_YN, MAX(CASE WHEN CQI_COMP_CD = '360' THEN CQI_COMP_YN END) AS D4_YN, MAX(CASE WHEN CQI_COMP_CD = '130' THEN CQI_COMP_YN END) AS D5_YN, MAX(CASE WHEN CQI_COMP_CD = '140' THEN CQI_COMP_YN END) AS D6_YN, MAX(CASE WHEN CQI_COMP_CD = '150' THEN CQI_COMP_YN END) AS D7_YN, MAX(CASE WHEN CQI_COMP_CD = '230' THEN CQI_COMP_YN END) AS D8_YN, MAX(CASE WHEN CQI_COMP_CD = '240' THEN CQI_COMP_YN END) AS D9_YN, MAX(CASE WHEN CQI_COMP_CD = '250' THEN CQI_COMP_YN END) AS D10_YN FROM PREV_COMP GROUP BY ORGID ) SELECT #{yy} AS YY , CO.DEPT_LOCT_CD , COMM.FN_CMN_CD('DEPT_LOCT_CD', CO.DEPT_LOCT_CD) AS DEPT_LOCT_NM , CBO.DPMT_CD , CBO.DPMT_NM , CO.ORGID , CO.ORGZ_NM -- 올해 값이 하나도 없으면(CUR_CNT=0) 전년도 값 사용, 있으면 올해 값 사용 , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D1_YN ELSE CA.D1_YN END AS D1_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D2_YN ELSE CA.D2_YN END AS D2_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D3_YN ELSE CA.D3_YN END AS D3_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D4_YN ELSE CA.D4_YN END AS D4_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D5_YN ELSE CA.D5_YN END AS D5_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D6_YN ELSE CA.D6_YN END AS D6_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D7_YN ELSE CA.D7_YN END AS D7_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D8_YN ELSE CA.D8_YN END AS D8_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D9_YN ELSE CA.D9_YN END AS D9_YN , CASE WHEN NVL(CA.CUR_CNT,0) = 0 THEN PA.D10_YN ELSE CA.D10_YN END AS D10_YN -- Master 제출/마감 상태 , NVL(MM.SUBMIT_YN, 'N') AS SUBMIT_YN , MM.SUBMIT_UID , MM.SUBMIT_DM , NVL(MM.CLOSE_YN, 'N') AS CLOSE_YN , MM.CLOSE_UID , MM.CLOSE_DM , RMK FROM COMM.COMM_ORGZ CO JOIN COMM.COMM_BACH_ORGZ CBO ON CO.ORGID = CBO.ORGID JOIN (SELECT ORGID FROM TABLE(COMM.FN_ORGZ_AUTH(#{loginUserIntgUid}, #{relatWokCd}, #{loginUserOrgid}, '', #{acsAlRngCd})) ) FOA ON CO.ORGID = FOA.ORGID LEFT JOIN CUR_AGG CA ON CA.ORGID = CO.ORGID LEFT JOIN PREV_AGG PA ON PA.ORGID = CO.ORGID LEFT JOIN UNIV.MCQI_MASTER MM ON MM.YY = #{yy} AND MM.ORGID = CO.ORGID
AND MM.PFLT_ID = #{pfltId}
AND MM.CQI_DIV_CD = '0001' WHERE CBO.COLL_CD = #{collCd} AND CBO.DPMT_CD = #{dpmtCd} AND CO.ORGID = #{mjCd} AND CO.DEPT_LOCT_CD = #{deptLoctCd}

mapper.update:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.mergeMcqiContDscList */
MERGE INTO UNIV.MCQI_CONT_DSC
    USING DUAL ON (YY = #{yy}
        AND ORGID = #{orgid})
    WHEN MATCHED THEN
        UPDATE
            SET D1_YN = #{d1Yn}
                ,D2_YN = #{d2Yn}
                ,D3_YN = #{d3Yn}
                ,D4_YN = #{d4Yn}
                ,D5_YN = #{d5Yn}
                ,D6_YN = #{d6Yn}
                ,D7_YN = #{d7Yn}
                ,D8_YN = #{d8Yn}
                ,D9_YN = #{d9Yn}
                ,D10_YN = #{d10Yn}
                ,CONT1 = #{cont1}
                ,CONT2 = #{cont2}
                ,CONT3 = #{cont3}
                ,CONT4 = #{cont4}
                ,CONT5 = #{cont5}
                ,CONT6 = #{cont6}
                ,CONT7 = #{cont7}
                ,CONT8 = #{cont8}
                ,RMK = #{rmk}
                ,LTST_UPD_UID = #{latestUserId}
                ,LTST_UPD_DM = SYSDATE
                ,LTST_UPD_IP = #{remoteAddr}
    WHEN NOT MATCHED THEN
        INSERT (
                YY
            ,ORGID
            ,D1_YN
            ,D2_YN
            ,D3_YN
            ,D4_YN
            ,D5_YN
            ,D6_YN
            ,D7_YN
            ,D8_YN
            ,D9_YN
            ,D10_YN
            ,CONT1
            ,CONT2
            ,CONT3
            ,CONT4
            ,CONT5
            ,CONT6
            ,CONT7
            ,CONT8
            ,CONT9
            ,CONT10
            ,CONT11
            ,RMK
            ,INPUT_UID
            ,INPUT_DM
            ,INPUT_IP
            ) VALUES (
                       #{yy}
                     ,#{orgid}
                     ,#{d1Yn}
                     ,#{d2Yn}
                     ,#{d3Yn}
                     ,#{d4Yn}
                     ,#{d5Yn}
                     ,#{d6Yn}
                     ,#{d7Yn}
                     ,#{d8Yn}
                     ,#{d9Yn}
                     ,#{d10Yn}
                     ,#{cont1}
                     ,#{cont2}
                     ,#{cont3}
                     ,#{cont4}
                     ,#{cont5}
                     ,#{cont6}
                     ,#{cont7}
                     ,#{cont8}
                     ,#{cont9}
                     ,#{cont10}
                     ,#{cont11}
                     ,#{rmk}
                     ,#{inputUserId}
                     ,SYSDATE
                     ,#{remoteAddr})

/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.updateMcqiContSubmit */
UPDATE UNIV.MCQI_CONT_DSC
SET SUBMIT_YN = '1'
  ,SUBMIT_UID = #{latestUserId}
  ,SUBMIT_DM = SYSDATE
  ,LTST_UPD_UID = #{latestUserId}
  ,LTST_UPD_DM = SYSDATE
  ,LTST_UPD_IP = #{remoteAddr}
WHERE YY = #{yy}
  AND ORGID = #{orgid}

/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.updateMcqiContSubmitCnl */
UPDATE UNIV.MCQI_CONT_DSC
SET SUBMIT_YN = NULL
  ,SUBMIT_UID = NULL
  ,SUBMIT_DM = NULL
  ,LTST_UPD_UID = #{latestUserId}
  ,LTST_UPD_DM = SYSDATE
  ,LTST_UPD_IP = #{remoteAddr}
WHERE YY = #{yy}
  AND ORGID = #{orgid}

/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.updateTcqiOrgzDsc */
UPDATE univ.MCQI_CONT_DSC
SET  close_yn = #{closeYn}
  ,close_uid = #{latestUserId}
  ,close_dm = SYSDATE
  ,ltst_upd_uid = #{latestUserId}    /* 최근수정사용자ID */
  ,ltst_upd_dm = SYSDATE           /* 최근수정일시 */
  ,ltst_upd_ip = #{remoteAddr}     /* 최근수정IP */
WHERE yy = #{yy}
  AND orgid = #{orgid}

mapper.select:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.findMcqiPfltAscDsc */ SELECT YY ,SEM_CD ,CQI_DIV_CD ,COMM.FN_CMN_CD('CQI_DIV_CD', CQI_DIV_CD) AS CQI_DIV_NM ,DET_MNGT_DSC_CD ,( select pcond_nm FROM univ.srec_bach_cmn_pcond_dsc sbcp where 1=1 AND sbcp.use_yn = '1' AND sbcp.pcond_ty_cd = '0001' AND sbcp.pgm_id = '3316' and sbcp.parm_cont = DET_MNGT_DSC_CD) AS DET_MNGT_DSC_NM ,PFLT_ID ,PFLT_ID AS before_Pflt_Id ,VEI.MEM_PSTN_NM as orgz_Nm ,VEI.WKGR_NM ,VEI.WKPS_NM ,COMM.FN_USER_NM(PFLT_ID) PFLT_NM ,MCQI.INPUT_UID ,MCQI.INPUT_DM ,MCQI.INPUT_IP ,MCQI.LTST_UPD_UID ,MCQI.LTST_UPD_DM ,MCQI.LTST_UPD_IP FROM UNIV.MCQI_PFLT_ASC_DSC MCQI , ADMI.VW_EMP_INFO VEI WHERE 1=1 AND MCQI.PFLT_ID = VEI.EMPID and YY = #{yy}
and CQI_DIV_CD = #{cqiDivCd}
and DET_MNGT_DSC_CD = #{detMngtDscCd}
and MCQI.PFLT_ID = #{pfltId}
order by YY , CQI_DIV_CD , DET_MNGT_DSC_CD

mapper.insert:
