       ,#{remoteAddr})

mapper.update:
/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.updateMcqiPfltAscDsc */
UPDATE univ.mcqi_pflt_asc_dsc
SET DET_MNGT_DSC_CD = #{detMngtDscCd}
  ,PFLT_ID = #{pfltId}
  ,ltst_upd_uid = #{latestUserId}    /* 최근수정사용자ID */
  ,ltst_upd_dm = SYSDATE           /* 최근수정일시 */
