    SUBMIT_UID = NULL,
    SUBMIT_DM  = NULL,
    LTST_UPD_UID = #{latestUserId},
    LTST_UPD_DM  = SYSDATE,
    LTST_UPD_IP  = #{remoteAddr}
WHERE YY = #{yy}
  AND ORGID = #{orgid}
  AND PFLT_ID = #{pfltId}
  AND CQI_DIV_CD = #{cqiDivCd}

UPDATE UNIV.MCQI_MASTER
SET CLOSE_YN = 'Y',
    CLOSE_UID = #{latestUserId},
    CLOSE_DM = SYSDATE,
    LTST_UPD_UID = #{latestUserId},
    LTST_UPD_DM = SYSDATE,
    LTST_UPD_IP = #{remoteAddr}
WHERE YY = #{yy}
  AND ORGID = #{orgid}
  AND PFLT_ID = #{pfltId}
  AND CQI_DIV_CD = #{cqiDivCd}

UPDATE UNIV.MCQI_COMP_DSC
SET CQI_COMP_YN = #{cqiCompYn},
    LTST_UPD_UID = #{latestUserId},
    LTST_UPD_DM  = SYSDATE,
    LTST_UPD_IP  = #{remoteAddr}
WHERE YY = #{yy}
  AND ORGID = #{orgid}
  AND PFLT_ID = #{pfltId}
  AND CQI_DIV_CD = #{cqiDivCd}
  AND CQI_COMP_CD = #{cqiCompCd}

UPDATE UNIV.MCQI_SECT_DSC
SET CONT = #{cont},
    SORT_ORD = #{sortOrd},
    LTST_UPD_UID = #{latestUserId},
    LTST_UPD_DM  = SYSDATE,
    LTST_UPD_IP  = #{remoteAddr}
WHERE YY = #{yy}
  AND ORGID = #{orgid}
  AND PFLT_ID = #{pfltId}
  AND CQI_DIV_CD = #{cqiDivCd}
  AND CQI_SECT_CD = #{cqiSectCd}
  AND CQI_TYPE_CD = #{cqiTypeCd}
  AND CHOI_CD = #{choiCd}

