/* kr.dku.univ.mcqi.tcqi.repository.TcqiMapper.findMcqiSectPrevPlan */
/* 전년도 TYPE='03'(이번년도개선계획) 조회 → 현재연도 TYPE='01'(전년도개선계획) 이월 */
SELECT CQI_SECT_CD
     , CQI_TYPE_CD     /* 서비스·JSP에서 TYPE='01' 로 취급 */
     , CHOI_CD
     , ANS_TYPE_CD
     , CONT
     , SORT_ORD
FROM UNIV.MCQI_SECT_DSC
WHERE YY          = #{yy}        /* 전년도(현재연도 - 1) 로 호출 */
  AND ORGID        = #{orgid}
  AND PFLT_ID      = #{pfltId}
  AND CQI_DIV_CD   = #{cqiDivCd}
  AND CQI_TYPE_CD  = '03'        /* 이번년도개선계획만 이월 소스로 사용 */
ORDER BY CQI_SECT_CD, ANS_TYPE_CD DESC, SORT_ORD, CHOI_CD

